#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& v) {
    size_t n = v.size(), i = 1;
    if (n < 2) return;
    while (i < n && v[i] == v[i-1]) i++;
    if (i < n && v[i] < v[i-1]) {
        while (i < n && v[i] <= v[i-1]) i++;
        std::reverse(v.begin(), v.begin() + i);
    }
    while (i < n && v[i-1] <= v[i]) i++;
    if (i == n) return;
    if (i * 4 > n || n - i < 80) {
        std::sort(v.begin() + i, v.end());
        std::inplace_merge(v.begin(), v.begin() + i, v.end());
    } else std::sort(v.begin(), v.end());
}

